var myDate=new Date,myMonth=myDate.getMonth()+1,myDay=myDate.getDate();getMonth=myMonth<10?"0"+String(myMonth):String(myMonth),getDay=myDay<10?"0"+String(myDay):String(myDay);var getType="S"+getMonth+getDay,geturl="/history/"+getMonth+".json";$(function(){$.ajax({type:"GET",url:geturl,dataType:"json",success:function(t){var e='<ul style="list-style: none;padding-inline-start: 0px;">';$.each(t[getType],function(t,n){e+='<li style="list-style: none;height:100px;">',e+='<p style="color: #858585;Font-style:italic;font-weight:lighter;float:left;width:100%;font-size: 14px;margin:0px; padding:0px;display:inline-block">',e+="<i >公元 </i>"+n.year+"年"+getMonth+"月"+getDay+"日</p>",e+='<p style="width:100%;float:left;margin:0px; padding:0px;display:inline-block" >',e+=n.title+'<i style="Font-style:normal;">。</i>',e+="</p></li>"}),e+="</ul>",$("#history-card").append(e)}})});